define(["jquery","core/notification","paygw_webirr/repository"],function($,Notification,Repository){var POLL_DELAY_MS=5e3,paymentState={};var init=function(component,paymentArea,itemId,description,sesskey){paymentState={component:component,paymentArea:paymentArea,itemId:itemId,sesskey:sesskey,paymentId:null,pollTimer:null};$("#payment-refresh-button").off("click").on("click",function(){checkPaymentStatus(false)});showActions(false);setStatus("info","Creating payment code...",true);Repository.getPaymentCode(component,paymentArea,itemId,description).then(function(response){if(response.success){paymentState.paymentId=response.paymentid;$("#payment-loading").hide();$("#payment-code-display").empty().append($("<div>").addClass("payment-code-title").text("WeBirr Payment Code")).append($("<div>").addClass("payment-code-large").text(response.paymentcode)).append($("<p>").addClass("payment-instructions").text("Use this payment code in your banking app to complete the payment."));waitAndCheckPaymentStatus()}else{setStatus("danger",response.error,false)}}).catch(Notification.exception)};var showActions=function(visible){$("#payment-actions").toggle(visible)};var setActionsDisabled=function(disabled){$("#payment-refresh-button").prop("disabled",disabled)};var setStatus=function(type,message,spinning){var status=$("#payment-status"),statusText=$("#payment-status-text");status.removeClass().addClass("alert alert-"+type);if(statusText.length){statusText.text(message);$("#payment-spinner").toggle(!!spinning)}else{status.text(message)}};var setDetail=function(message){$("#payment-detail").text(message)};var waitAndCheckPaymentStatus=function(){clearTimeout(paymentState.pollTimer);showActions(false);setActionsDisabled(true);setStatus("info","Waiting for payment confirmation...",true);setDetail("Checking payment status in about 5 seconds.");paymentState.pollTimer=setTimeout(function(){checkPaymentStatus(true)},POLL_DELAY_MS)};var checkPaymentStatus=function(automatic){if(!paymentState.paymentId){return}clearTimeout(paymentState.pollTimer);setActionsDisabled(true);setStatus("info",automatic?"Checking payment status...":"Refreshing payment status...",true);setDetail("");Repository.getPaymentStatus(paymentState.paymentId).then(function(response){if(response.success){if(response.complete){setStatus("success","Your payment was successful.",false);setTimeout(function(){window.location.href=M.cfg.wwwroot+"/payment/gateway/webirr/success.php?component="+encodeURIComponent(paymentState.component)+"&paymentarea="+encodeURIComponent(paymentState.paymentArea)+"&itemid="+encodeURIComponent(paymentState.itemId)+"&sesskey="+encodeURIComponent(paymentState.sesskey)},2e3)}else{setStatus("warning","Payment not received yet.",true);setDetail("");showActions(true);setActionsDisabled(true);paymentState.pollTimer=setTimeout(function(){checkPaymentStatus(true)},POLL_DELAY_MS)}}else{setStatus("danger",response.error,false);showActions(true);setActionsDisabled(false)}}).catch(function(error){showActions(true);setActionsDisabled(false);Notification.exception(error)})};return{init:init}});
